Certainly, here’s a **basic implementation** of `minigit` as typically specified in a "mini-git" assignment. This covers initializing a repository, adding/removing files, committing changes, and viewing history, based on commonly seen version 1 specifications.

**Notes:**
- This solution is based on likely requirements. You may need to adjust paths or logic to exactly fit your provided `SPEC-v1.txt` and `test-v1.sh`.
- Run `make` to build. The compiled file will be named `minigit` and should be executed as `./minigit`.
- Only uses standard C and minimal POSIX.

---

**FILE: `minigit.c`**
```c
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <sys/stat.h>
#include <dirent.h>
#include <unistd.h>

#define MINIGIT_DIR ".minigit"
#define INDEX_FILE ".minigit/index"
#define COMMITS_DIR ".minigit/commits"
#define HASH_LEN 8
#define MSG_LEN 128

typedef struct {
    char filename[128];
    char hash[HASH_LEN + 1];
} IndexEntry;

void hash_file(const char* filename, char* hash_out) {
    // Simple hash function for demo - not cryptographically secure!
    FILE* f = fopen(filename, "rb");
    if(!f) { strcpy(hash_out, "00000000"); return; }
    unsigned long hash = 5381;
    int c;
    while((c = fgetc(f)) != EOF)
        hash = ((hash << 5) + hash) + c;
    fclose(f);
    sprintf(hash_out, "%08lx", hash & 0xffffffff);
}

int file_exists(const char* path) {
    struct stat st;
    return stat(path, &st) == 0;
}

void ensure_minigit() {
    struct stat st = {0};
    if (stat(MINIGIT_DIR, &st) == -1) {
        mkdir(MINIGIT_DIR, 0700);
        mkdir(COMMITS_DIR, 0700);
        FILE* f = fopen(INDEX_FILE, "w"); if(f) fclose(f);
        printf("Initialized empty minigit repository.\n");
    } else {
        printf("minigit repository already exists.\n");
    }
}

void load_index(IndexEntry** entries, int* count) {
    *count = 0;
    *entries = NULL;
    FILE* f = fopen(INDEX_FILE, "r");
    if (!f) return;
    char buf[256];
    while(fgets(buf, sizeof(buf), f)) {
        (*entries) = realloc(*entries, ((*count)+1)*sizeof(IndexEntry));
        sscanf(buf, "%127s %8s", (*entries)[*count].filename, (*entries)[*count].hash);
        (*count)++;
    }
    fclose(f);
}

void save_index(IndexEntry* entries, int count) {
    FILE* f = fopen(INDEX_FILE, "w");
    for(int i = 0; i < count; ++i)
        fprintf(f, "%s %s\n", entries[i].filename, entries[i].hash);
    fclose(f);
}

void cmd_add(const char* filename) {
    if (!file_exists(filename)) {
        printf("File does not exist: %s\n", filename);
        return;
    }
    IndexEntry* entries = NULL;
    int count;
    load_index(&entries, &count);
    for(int i=0; i<count; ++i) {
        if(strcmp(entries[i].filename, filename) == 0) {
            printf("File '%s' already added.\n", filename);
            free(entries);
            return;
        }
    }
    entries = realloc(entries, (count+1)*sizeof(IndexEntry));
    strcpy(entries[count].filename, filename);
    char hash[HASH_LEN+1];
    hash_file(filename, hash);
    strcpy(entries[count].hash, hash);
    save_index(entries, count+1);
    free(entries);
    printf("Added '%s'.\n", filename);
}

void cmd_rm(const char* filename) {
    IndexEntry* entries = NULL;
    int count, found=0;
    load_index(&entries, &count);
    int j=0;
    for(int i=0; i<count; ++i) {
        if(strcmp(entries[i].filename, filename) != 0)
            entries[j++] = entries[i];
        else
            found = 1;
    }
    if(!found) {
        printf("File '%s' not in index.\n", filename);
        free(entries);
        return;
    }
    save_index(entries, j);
    free(entries);
    printf("Removed '%s' from index.\n", filename);
}

void copy_file(const char* src, const char* dst) {
    FILE* fsrc = fopen(src, "rb");
    FILE* fdst = fopen(dst, "wb");
    if (!fsrc || !fdst) { if(fsrc)fclose(fsrc); if(fdst)fclose(fdst); return; }
    char buf[1024];
    size_t n;
    while((n = fread(buf,1,sizeof(buf),fsrc)) > 0)
        fwrite(buf,1,n,fdst);
    fclose(fsrc); fclose(fdst);
}

int next_commit_id() {
    int maxid = 0;
    DIR* d = opendir(COMMITS_DIR);
    struct dirent* de;
    while((de = readdir(d))) {
        int id = 0;
        if(sscanf(de->d_name, "%d", &id) == 1 && id > maxid)
            maxid = id;
    }
    closedir(d);
    return maxid+1;
}

void cmd_commit(const char* msg) {
    IndexEntry* entries = NULL;
    int count;
    load_index(&entries, &count);
    if (count == 0) {
        printf("Nothing to commit.\n");
        free(entries);
        return;
    }
    int commit_id = next_commit_id();
    char commit_dir[256];
    sprintf(commit_dir, "%s/%d", COMMITS_DIR, commit_id);
    mkdir(commit_dir, 0700);
    // Save metadata
    char metafile[256];
    sprintf(metafile, "%s/meta", commit_dir);
    FILE* mf = fopen(metafile, "w");
    fprintf(mf, "msg %s\n", msg);
    for(int i=0;i<count;++i)
        fprintf(mf, "%s %s\n", entries[i].filename, entries[i].hash);
    fclose(mf);
    // Save file snapshots
    for(int i=0;i<count;++i) {
        char dst[256];
        sprintf(dst, "%s/%s", commit_dir, entries[i].filename);
        copy_file(entries[i].filename, dst);
    }
    free(entries);
    printf("Committed as %d: %s\n", commit_id, msg);
}

void cmd_log() {
    DIR* d = opendir(COMMITS_DIR);
    struct dirent* de;
    int ids[1024], cnt=0;
    while((de = readdir(d))) {
        int id = 0;
        if(sscanf(de->d_name, "%d", &id) == 1)
            ids[cnt++] = id;
    }
    closedir(d);
    // print in reverse
    for(int i = cnt-1; i >= 0; --i) {
        char metafile[256];
        sprintf(metafile, "%s/%d/meta", COMMITS_DIR, ids[i]);
        FILE* mf = fopen(metafile, "r");
        if (!mf) continue;
        char buf[256];
        fgets(buf, sizeof(buf), mf);
        buf[strcspn(buf,"\n")]=0;
        printf("Commit %d: %s\n", ids[i], buf+4);
        fclose(mf);
    }
}

void print_usage() {
    puts("minigit usage:");
    puts("  ./minigit init");
    puts("  ./minigit add <filename>");
    puts("  ./minigit rm <filename>");
    puts("  ./minigit commit <msg>");
    puts("  ./minigit log");
}

int main(int argc, char* argv[]) {
    if(argc < 2) { print_usage(); return 1; }
    if(strcmp(argv[1],"init")==0) {
        ensure_minigit();
    } else if(strcmp(argv[1],"add")==0 && argc==3) {
        cmd_add(argv[2]);
    } else if(strcmp(argv[1],"rm")==0 && argc==3) {
        cmd_rm(argv[2]);
    } else if(strcmp(argv[1],"commit")==0 && argc==3) {
        cmd_commit(argv[2]);
    } else if(strcmp(argv[1],"log")==0) {
        cmd_log();
    } else {
        print_usage();
        return 1;
    }
    return 0;
}
```

